b64 = ""

with open('index.html', 'r', encoding='utf-8') as f:
    html = f.read()

# Substituir img anterior ou SVG antigo
import re
old = re.search(r'  <div class="logo">.*?</div>', html)
if old:
    new_logo = '  <div class="logo"><img src="data:image/png;base64,{b64}" alt="MF Envios" style="height:52px;width:auto;object-fit:contain;" /></div>'
    html = html[:old.start()] + new_logo + html[old.end():]
    with open('index.html', 'w', encoding='utf-8') as f:
        f.write(html)
    print('OK - logo maior aplicado!')
else:
    print('X - logo nao encontrado')
